mapper.select:
select id, tenant_id, template_code, template_name, template_type, biz_type, file_format_type, charset, target_charset, with_bom, line_separator, delimiter, quote_char, escape_char, record_length, header_rows, footer_rows, header_template, trailer_template, checksum_type, compress_type, encrypt_type, naming_rule, field_mappings, validation_rule_set, default_query_code, default_query_sql, query_param_schema, streaming_enabled, page_size, fetch_size, enabled, version, description, created_by, updated_by, created_at, updated_at from batch.file_template_config where tenant_id = #{tenantId}
and template_code = #{templateCode}
and template_type = #{templateType}
and enabled = #{enabled}
order by template_code asc, version desc
